{
  "name": "CalmaVibe",
  "description": "Una aplicación web diseñada para brindar apoyo, paz y acompañamiento a personas que atraviesan momentos de ansiedad o depresión, con herramientas de IA, música relajante y diario personal.",
  "requestFramePermissions": [
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppView {
  WELCOME = 'welcome',
  AUTH = 'auth',
  DASHBOARD = 'dashboard',
  CHAT = 'chat',
  PROFILE = 'profile',
  MUSIC = 'music',
  BOOKS = 'books',
  JOURNAL = 'journal'
}

export interface UserProfile {
  fullName: string;
  photoUrl: string;
  medicalInfo: string;
  emergencyContact: string;
  emergencyPhone: string;
}

export interface Message {
  role: 'user' | 'model';
  text: string;
  timestamp: number;
}

export interface JournalEntry {
  id: string;
  date: string;
  title: string;
  content: string;
}

export interface Book {
  id: string;
  title: string;
  author: string;
  description: string;
  coverUrl: string;
}

export interface Track {
  id: string;
  title: string;
  artist: string;
  url: string;
  type: 'binaural' | 'nature' | 'meditation';
}

import React, { useState, useEffect } from 'react';
import { AppView, UserProfile } from './types';
import Navigation from './components/Navigation';
import Welcome from './components/Welcome';
import Auth from './components/Auth';
import ChatAI from './components/ChatAI';
import Profile from './components/Profile';
import Music from './components/Music';
import Books from './components/Books';
import Journal from './components/Journal';

const App: React.FC = () => {
  const [currentView, setCurrentView] = useState<AppView>(AppView.WELCOME);
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [userProfile, setUserProfile] = useState<UserProfile>({
    fullName: 'Usuario',
    photoUrl: 'https://picsum.photos/seed/user/200/200',
    medicalInfo: '',
    emergencyContact: '',
    emergencyPhone: ''
  });

  // Background image matches the calm lake feeling described
  const backgroundUrl = "https://images.unsplash.com/photo-1506126613408-eca07ce68773?auto=format&fit=crop&q=80&w=2000";

  const renderView = () => {
    switch (currentView) {
      case AppView.WELCOME:
        return <Welcome onStart={() => setCurrentView(AppView.AUTH)} />;
      case AppView.AUTH:
        return <Auth onLogin={() => {
          setIsAuthenticated(true);
          setCurrentView(AppView.DASHBOARD);
        }} />;
      case AppView.DASHBOARD:
        return (
          <div className="flex flex-col items-center justify-center min-h-[70vh] gap-6 text-white text-center px-4">
            <h1 className="text-4xl md:text-5xl font-bold drop-shadow-lg">Hola, {userProfile.fullName.split(' ')[0]}</h1>
            <p className="text-xl drop-shadow-md">¿Cómo te sientes hoy? Estamos aquí para acompañarte.</p>
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4 w-full max-w-2xl mt-8">
              <button onClick={() => setCurrentView(AppView.CHAT)} className="glass-effect p-6 rounded-2xl flex flex-col items-center gap-2 hover:bg-white/30 transition-all group">
                <span className="text-4xl group-hover:scale-110 transition-transform">💬</span>
                <span className="font-semibold">Chat IA</span>
              </button>
              <button onClick={() => setCurrentView(AppView.PROFILE)} className="glass-effect p-6 rounded-2xl flex flex-col items-center gap-2 hover:bg-white/30 transition-all group">
                <span className="text-4xl group-hover:scale-110 transition-transform">👤</span>
                <span className="font-semibold">Perfil</span>
              </button>
              <button onClick={() => setCurrentView(AppView.MUSIC)} className="glass-effect p-6 rounded-2xl flex flex-col items-center gap-2 hover:bg-white/30 transition-all group">
                <span className="text-4xl group-hover:scale-110 transition-transform">🎵</span>
                <span className="font-semibold">Música</span>
              </button>
              <button onClick={() => setCurrentView(AppView.BOOKS)} className="glass-effect p-6 rounded-2xl flex flex-col items-center gap-2 hover:bg-white/30 transition-all group">
                <span className="text-4xl group-hover:scale-110 transition-transform">📚</span>
                <span className="font-semibold">Libros</span>
              </button>
              <button onClick={() => setCurrentView(AppView.JOURNAL)} className="glass-effect p-6 rounded-2xl flex flex-col items-center gap-2 hover:bg-white/30 transition-all group">
                <span className="text-4xl group-hover:scale-110 transition-transform">✍️</span>
                <span className="font-semibold">Diario</span>
              </button>
            </div>
          </div>
        );
      case AppView.CHAT: return <ChatAI />;
      case AppView.PROFILE: return <Profile profile={userProfile} onUpdate={setUserProfile} />;
      case AppView.MUSIC: return <Music />;
      case AppView.BOOKS: return <Books />;
      case AppView.JOURNAL: return <Journal />;
      default: return <Welcome onStart={() => setCurrentView(AppView.AUTH)} />;
    }
  };

  return (
    <div 
      className="min-h-screen w-full relative flex flex-col"
      style={{
        backgroundImage: `linear-gradient(rgba(0,0,0,0.1), rgba(0,0,0,0.3)), url(${backgroundUrl})`,
        backgroundSize: 'cover',
        backgroundPosition: 'center',
        backgroundAttachment: 'fixed'
      }}
    >
      <header className="p-4 md:p-6 flex justify-between items-center text-white z-10">
        <button onClick={() => setCurrentView(AppView.DASHBOARD)} className="text-2xl font-bold tracking-tight italic">
          CalmaVibe
        </button>
        {isAuthenticated && (
          <button onClick={() => setCurrentView(AppView.PROFILE)} className="w-10 h-10 rounded-full overflow-hidden border-2 border-white/50">
            <img src={userProfile.photoUrl} alt="Avatar" className="w-full h-full object-cover" />
          </button>
        )}
      </header>

      <main className="flex-1 overflow-y-auto px-4 py-8 max-w-6xl mx-auto w-full z-10">
        {renderView()}
      </main>

      {isAuthenticated && currentView !== AppView.WELCOME && currentView !== AppView.AUTH && (
        <Navigation currentView={currentView} setView={setCurrentView} />
      )}
    </div>
  );
};

export default App;

import React from 'react';
import { AppView } from '../types';

interface NavigationProps {
  currentView: AppView;
  setView: (view: AppView) => void;
}

const Navigation: React.FC<NavigationProps> = ({ currentView, setView }) => {
  const navItems = [
    { id: AppView.DASHBOARD, label: 'Inicio', icon: '🏠' },
    { id: AppView.CHAT, label: 'Chat', icon: '💬' },
    { id: AppView.MUSIC, label: 'Música', icon: '🎵' },
    { id: AppView.JOURNAL, label: 'Diario', icon: '✍️' },
    { id: AppView.BOOKS, label: 'Libros', icon: '📚' },
  ];

  return (
    <nav className="fixed bottom-6 left-1/2 -translate-x-1/2 glass-effect rounded-full px-4 py-2 flex gap-1 md:gap-4 z-50 shadow-2xl">
      {navItems.map((item) => (
        <button
          key={item.id}
          onClick={() => setView(item.id)}
          className={`flex flex-col items-center p-2 rounded-full min-w-[60px] md:min-w-[80px] transition-all ${
            currentView === item.id ? 'active-nav scale-110' : 'hover:bg-white/10'
          }`}
        >
          <span className="text-xl">{item.icon}</span>
          <span className="text-[10px] md:text-xs font-medium text-white">{item.label}</span>
        </button>
      ))}
    </nav>
  );
};

export default Navigation;

