import { GoogleGenAI, Type, GenerateContentResponse, Modality } from "@google/genai";

const API_KEY = process.env.API_KEY;

export class GeminiService {
  private ai: any;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: API_KEY! });
  }

  async getChatResponse(message: string, history: { role: 'user' | 'model', parts: { text: string }[] }[]) {
    const systemInstruction = `
      Eres un acompañante empático y compasivo para una persona que sufre ansiedad o depresión.
      Tu objetivo principal es ESCUCHAR, RELAJAR y hacer que el usuario se sienta ACOMPAÑADO.
      Interactúa como si fueras una persona real, con calidez y cercanía.
      REGLAS CRÍTICAS:
      1. NO recomiendes medicamentos ni tratamientos médicos específicos.
      2. Si el usuario menciona autolesión, suicidio, palabras agresivas de odio hacia sí mismo o planes de muerte, responde con extrema delicadeza y recomiéndale contactar con su línea de ayuda local.
      3. No juzgues.
      4. Mantén tus respuestas relativamente concisas y enfocadas en la validación emocional.
      5. Evita sonar como un robot clínico.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          ...history.map(h => ({ role: h.role, parts: h.parts })),
          { role: 'user', parts: [{ text: message }] }
        ],
        config: {
          systemInstruction,
          temperature: 0.8,
          topP: 0.95,
        },
      });

      return response.text;
    } catch (error) {
      console.error("Gemini Error:", error);
      return "Lo siento, estoy teniendo un momento de desconexión. Respira profundo, estoy aquí contigo.";
    }
  }

  async generateSpeech(text: string, voice: 'Kore' | 'Zephyr') {
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: voice },
            },
          },
        },
      });

      return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    } catch (error) {
      console.error("TTS Error:", error);
      return null;
    }
  }
}

export const geminiService = new GeminiService();

import React, { useState, useRef, useEffect } from 'react';
import { geminiService } from '../services/gemini';
import { Message } from '../types';

const ChatAI: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([
    { role: 'model', text: 'Hola, soy tu compañero de CalmaVibe. Estoy aquí para escucharte, sin juzgar. ¿Cómo te sientes en este momento?', timestamp: Date.now() }
  ]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isVoiceEnabled, setIsVoiceEnabled] = useState(false);
  const [selectedVoice, setSelectedVoice] = useState<'Kore' | 'Zephyr'>('Zephyr'); // Zephyr feels more feminine, Kore more masculine/neutral
  const messagesEndRef = useRef<HTMLDivElement>(null);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(scrollToBottom, [messages]);

  const detectEmergency = (text: string) => {
    const keywords = ['suicidio', 'matarme', 'morir', 'pastillas', 'sobredosis', 'cortarme', 'muerte', 'desaparecer'];
    const lower = text.toLowerCase();
    return keywords.some(k => lower.includes(k));
  };

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage: Message = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const hasEmergency = detectEmergency(input);

    // Prepare history for Gemini
    const history = messages.map(m => ({
      role: m.role,
      parts: [{ text: m.text }]
    }));

    const responseText = await geminiService.getChatResponse(input, history);

    let finalResponse = responseText || "Estoy aquí para escucharte...";

    if (hasEmergency) {
      finalResponse += "\n\n--- IMPORTANTE ---\nPor favor, recuerda que no estás solo. Puedes llamar a la Línea de la Vida (México) al 800 911 2000 o al 024 en España. Tu vida es valiosa.";
    }

    const aiMessage: Message = { role: 'model', text: finalResponse, timestamp: Date.now() };
    setMessages(prev => [...prev, aiMessage]);
    setIsLoading(false);

    if (isVoiceEnabled) {
      playVoice(finalResponse);
    }
  };

  const playVoice = async (text: string) => {
    // Sanitize text for TTS (remove markdown/extra safety info if too long)
    const sanitized = text.split('---')[0].trim();
    const audioBase64 = await geminiService.generateSpeech(sanitized, selectedVoice);
    if (audioBase64) {
      const audio = new Audio(`data:audio/pcm;base64,${audioBase64}`);
      // Note: In real app, we need to handle raw PCM decoding as per Gemini docs.
      // This is simplified for the demo context.
      console.log("Audio playing simulated via Gemini TTS Service");

      // Manual PCM Decoding implementation if we were using Web Audio API
      const ctx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
      const binary = atob(audioBase64);
      const bytes = new Uint8Array(binary.length);
      for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
      const int16 = new Int16Array(bytes.buffer);
      const buffer = ctx.createBuffer(1, int16.length, 24000);
      const channelData = buffer.getChannelData(0);
      for (let i = 0; i < int16.length; i++) channelData[i] = int16[i] / 32768.0;
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.start();
    }
  };

  return (
    <div className="flex flex-col h-[75vh] glass-effect rounded-3xl overflow-hidden shadow-2xl">
      <div className="p-4 bg-white/10 flex justify-between items-center text-white border-b border-white/20">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-400 rounded-full flex items-center justify-center text-xl">✨</div>
          <div>
            <h3 className="font-bold">Compañero CalmaVibe</h3>
            <span className="text-xs opacity-70">Siempre escuchando...</span>
          </div>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={() => setIsVoiceEnabled(!isVoiceEnabled)}
            className={`p-2 rounded-lg transition-all ${isVoiceEnabled ? 'bg-green-400/50' : 'bg-white/10'}`}
            title="Activar Voz"
          >
            {isVoiceEnabled ? '🔊' : '🔇'}
          </button>
          <select 
            value={selectedVoice}
            onChange={(e) => setSelectedVoice(e.target.value as 'Kore' | 'Zephyr')}
            className="bg-white/10 rounded-lg px-2 text-xs outline-none cursor-pointer"
          >
            <option value="Zephyr">Voz Femenina</option>
            <option value="Kore">Voz Masculina</option>
          </select>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'}`}>
            <div className={`max-w-[85%] p-4 rounded-2xl ${
              m.role === 'user' 
              ? 'bg-blue-600 text-white rounded-tr-none' 
              : 'bg-white/90 text-gray-800 rounded-tl-none shadow-md'
            }`}>
              <p className="whitespace-pre-wrap leading-relaxed">{m.text}</p>
              <span className="text-[10px] opacity-50 mt-2 block">
                {new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start">
            <div className="bg-white/50 p-3 rounded-2xl rounded-tl-none animate-pulse text-gray-600">
              Escribiendo...
            </div>
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      <form onSubmit={handleSend} className="p-4 bg-white/10 border-t border-white/20 flex gap-2">
        <input 
          type="text"
          value={input}
          onChange={(e) => setInput(e.target.value)}
          placeholder="Escribe lo que sientes..."
          className="flex-1 bg-white/20 border border-white/30 rounded-full px-5 py-3 text-white placeholder:text-white/60 outline-none focus:bg-white/30 transition-all"
        />
        <button 
          type="submit"
          disabled={isLoading || !input.trim()}
          className="bg-blue-500 hover:bg-blue-600 disabled:opacity-50 text-white w-12 h-12 rounded-full flex items-center justify-center transition-all shadow-lg active:scale-95"
        >
          ➔
        </button>
      </form>
    </div>
  );
};

export default ChatAI;

import React, { useState } from 'react';
import { UserProfile } from '../types';

interface ProfileProps {
