            key={track.id} 
            className={`flex items-center justify-between p-4 rounded-2xl transition-all cursor-pointer ${
              currentTrack?.id === track.id ? 'bg-white/30 scale-[1.02]' : 'bg-white/10 hover:bg-white/20'
