            <h3 className="text-xl font-bold">{currentTrack.title}</h3>
            <audio 
              src={currentTrack.url} 
              autoPlay={isPlaying} 
              controls 
              className="w-full mt-2 filter brightness-150 contrast-50"
              onPlay={() => setIsPlaying(true)}
              onPause={() => setIsPlaying(false)}
            />
          </div>
        </div>
      )}
    </div>
  );
};

