      <div className="mt-12 p-6 bg-white/10 rounded-2xl border border-white/5 flex items-center gap-4">
        <div className="text-4xl">🧘‍♀️</div>
        <div>
          <h4 className="font-bold">Consejo de Meditación</h4>
          <p className="text-sm opacity-70">No intentes detener tus pensamientos. Solo obsérvalos pasar como si fueran nubes en el cielo y vuelve suavemente a tu respiración.</p>
        </div>
      </div>
    </div>
  );
};

