import React, { useState, useEffect } from 'react';
import { ForumPost, ForumComment, UserProfile } from '../types';

interface ForumProps {
  userProfile: UserProfile;
}

const CATEGORIES = ['General', 'Ansiedad', 'Logros', 'Consejos', 'Depresión'];

const Forum: React.FC<ForumProps> = ({ userProfile }) => {
  const [posts, setPosts] = useState<ForumPost[]>([]);
  const [comments, setComments] = useState<ForumComment[]>([]);
  const [isAdding, setIsAdding] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newContent, setNewContent] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('General');
  const [filterCategory, setFilterCategory] = useState('Todas');
  const [activePostId, setActivePostId] = useState<string | null>(null);
  const [newComment, setNewComment] = useState('');

  useEffect(() => {
    const savedPosts = localStorage.getItem('calmavibe_forum_posts');
    const savedComments = localStorage.getItem('calmavibe_forum_comments');

    if (savedPosts) {
      setPosts(JSON.parse(savedPosts));
    } else {
      // Posts iniciales de ejemplo
      const initialPosts: ForumPost[] = [
        {
          id: '1',
          author: 'Sofía',
          authorPhoto: 'https://picsum.photos/seed/sofia/100/100',
          date: 'Hoy',
          title: 'Hoy logré salir a caminar',
          content: 'Llevaba tres días sin fuerzas, pero hoy pude dar una vuelta de 10 minutos. Me siento orgullosa.',
          likes: 12,
          category: 'Logros'
        },
        {
          id: '2',
          author: 'Carlos',
          authorPhoto: 'https://picsum.photos/seed/carlos/100/100',
          date: 'Ayer',
          title: 'Consejo para respirar',
          content: 'Cuando siento que el pecho se cierra, uso la técnica 4-7-8. Realmente me ayuda a bajar las pulsaciones.',
          likes: 24,
          category: 'Consejos'
        }
      ];
      setPosts(initialPosts);
      localStorage.setItem('calmavibe_forum_posts', JSON.stringify(initialPosts));
    }

    if (savedComments) setComments(JSON.parse(savedComments));
  }, []);

  const savePosts = (updated: ForumPost[]) => {
    setPosts(updated);
    localStorage.setItem('calmavibe_forum_posts', JSON.stringify(updated));
  };

  const saveComments = (updated: ForumComment[]) => {
    setComments(updated);
    localStorage.setItem('calmavibe_forum_comments', JSON.stringify(updated));
  };

  const handleAddPost = () => {
    if (!newTitle.trim() || !newContent.trim()) return;
    const post: ForumPost = {
      id: Date.now().toString(),
      author: userProfile.fullName,
      authorPhoto: userProfile.photoUrl,
      date: 'Recién',
      title: newTitle,
      content: newContent,
      likes: 0,
      category: selectedCategory
    };
    savePosts([post, ...posts]);
    setNewTitle('');
    setNewContent('');
    setIsAdding(false);
  };

  const handleLike = (id: string, e: React.MouseEvent) => {
    e.stopPropagation();
    savePosts(posts.map(p => p.id === id ? { ...p, likes: p.likes + 1 } : p));
  };

  const handleAddComment = (postId: string) => {
    if (!newComment.trim()) return;
    const comment: ForumComment = {
      id: Date.now().toString(),
      postId,
      author: userProfile.fullName,
      date: 'Ahora',
      content: newComment
    };
    saveComments([...comments, comment]);
    setNewComment('');
  };

  const filteredPosts = filterCategory === 'Todas' 
    ? posts 
    : posts.filter(p => p.category === filterCategory);

  return (
    <div className="glass-effect rounded-3xl p-6 md:p-8 text-white shadow-2xl max-w-4xl mx-auto animate-fade-in min-h-[70vh]">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div>
          <h2 className="text-3xl font-bold">Comunidad Calma</h2>
          <p className="text-sm opacity-70 italic">Un lugar seguro para compartir y sanar juntos.</p>
        </div>
        {!isAdding && (
          <button 
            onClick={() => setIsAdding(true)}
            className="bg-white text-blue-700 px-6 py-2 rounded-full font-bold shadow-lg hover:scale-105 transition-all"
          >
            + Compartir Experiencia
          </button>
        )}
      </div>

      <div className="mb-8 flex overflow-x-auto no-scrollbar gap-2 pb-2">
        <button 
          onClick={() => setFilterCategory('Todas')}
          className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all whitespace-nowrap ${
            filterCategory === 'Todas' ? 'bg-white text-blue-700' : 'bg-white/10 hover:bg-white/20'
          }`}
        >
          Todas
        </button>
        {CATEGORIES.map(cat => (
          <button 
            key={cat}
            onClick={() => setFilterCategory(cat)}
            className={`px-4 py-1.5 rounded-full text-sm font-medium transition-all whitespace-nowrap ${
              filterCategory === cat ? 'bg-white text-blue-700' : 'bg-white/10 hover:bg-white/20'
            }`}
          >
            {cat}
          </button>
        ))}
      </div>

      {isAdding ? (
        <div className="bg-white/20 p-6 rounded-2xl animate-fade-in space-y-4">
          <div className="flex gap-2 mb-2">
            {CATEGORIES.map(cat => (
              <button 
                key={cat}
                onClick={() => setSelectedCategory(cat)}
                className={`text-[10px] px-3 py-1 rounded-full border transition-all ${
                  selectedCategory === cat ? 'bg-blue-400 border-white' : 'bg-transparent border-white/30'
                }`}
              >
                {cat}
              </button>
            ))}
          </div>
          <input 
            type="text"
            value={newTitle}
            onChange={(e) => setNewTitle(e.target.value)}
            placeholder="Título de tu historia..."
            className="w-full bg-transparent border-b border-white/30 text-xl font-bold py-2 outline-none placeholder:text-white/40"
          />
          <textarea 
            value={newContent}
            onChange={(e) => setNewContent(e.target.value)}
            placeholder="¿Qué te gustaría compartir con la comunidad?"
            className="w-full bg-transparent h-40 outline-none resize-none leading-relaxed placeholder:text-white/40"
          />
          <div className="flex justify-end gap-4">
            <button onClick={() => setIsAdding(false)} className="px-4 py-2 opacity-70">Cancelar</button>
            <button onClick={handleAddPost} className="bg-blue-500 px-8 py-2 rounded-xl font-bold shadow-md hover:bg-blue-600 transition-all">Publicar</button>
          </div>
        </div>
      ) : (
        <div className="space-y-6">
          {filteredPosts.length === 0 ? (
            <div className="py-20 text-center opacity-60">
              <span className="text-5xl mb-4 block">🍃</span>
              <p>Aún no hay historias en esta categoría. <br/> ¡Sé el primero en compartir!</p>
            </div>
          ) : (
            filteredPosts.map((post) => (
              <div 
                key={post.id} 
                className="bg-white/10 rounded-2xl p-5 hover:bg-white/15 transition-all cursor-pointer border border-white/5"
                onClick={() => setActivePostId(activePostId === post.id ? null : post.id)}
              >
                <div className="flex items-center gap-3 mb-4">
                  <img src={post.authorPhoto} alt={post.author} className="w-8 h-8 rounded-full border border-white/20" />
                  <div>
                    <h4 className="text-sm font-bold">{post.author}</h4>
                    <span className="text-[10px] opacity-60 uppercase">{post.date} • {post.category}</span>
                  </div>
                </div>
                <h3 className="text-xl font-bold mb-3">{post.title}</h3>
                <p className="text-sm opacity-80 leading-relaxed mb-4">{post.content}</p>

                <div className="flex items-center gap-6 text-xs font-semibold">
                  <button 
                    onClick={(e) => handleLike(post.id, e)}
                    className="flex items-center gap-1.5 hover:text-blue-200 transition-colors"
                  >
                    ❤️ {post.likes}
                  </button>
                  <div className="flex items-center gap-1.5 opacity-70">
                    💬 {comments.filter(c => c.postId === post.id).length} comentarios
                  </div>
                </div>

                {activePostId === post.id && (
                  <div className="mt-6 pt-6 border-t border-white/10 space-y-4 animate-fade-in" onClick={e => e.stopPropagation()}>
                    <div className="space-y-3">
                      {comments.filter(c => c.postId === post.id).map(comment => (
                        <div key={comment.id} className="bg-black/10 p-3 rounded-xl">
                          <div className="flex justify-between text-[10px] opacity-60 mb-1">
                            <span className="font-bold">{comment.author}</span>
                            <span>{comment.date}</span>
                          </div>
                          <p className="text-xs">{comment.content}</p>
                        </div>
                      ))}
                    </div>
                    <div className="flex gap-2">
                      <input 
                        type="text" 
                        value={newComment}
                        onChange={(e) => setNewComment(e.target.value)}
                        placeholder="Escribe un comentario de apoyo..."
                        className="flex-1 bg-white/10 border border-white/20 rounded-full px-4 py-2 text-xs outline-none"
                      />
                      <button 
                        onClick={() => handleAddComment(post.id)}
                        className="bg-blue-500 p-2 rounded-full text-sm"
                      >
                        ➔
                      </button>
                    </div>
                  </div>
                )}
              </div>
            ))
          )}
        </div>
      )}
    </div>
  );
};

export default Forum;

import React, { useState, useRef, useEffect } from 'react';
import { geminiService } from '../services/gemini';
import { Message } from '../types';

const STORAGE_KEY = 'calmavibe_chat_history';
const MAX_HISTORY_MESSAGES = 50;

const ChatAI: React.FC = () => {
  const [messages, setMessages] = useState<Message[]>([]);
  const [input, setInput] = useState('');
  const [isLoading, setIsLoading] = useState(false);
  const [isVoiceEnabled, setIsVoiceEnabled] = useState(false);
  const [selectedVoice, setSelectedVoice] = useState<'Kore' | 'Zephyr'>('Zephyr');
  const messagesEndRef = useRef<HTMLDivElement>(null);

  // Cargar historial al montar el componente
  useEffect(() => {
    const savedHistory = localStorage.getItem(STORAGE_KEY);
    if (savedHistory) {
      try {
        const parsed = JSON.parse(savedHistory);
        if (Array.isArray(parsed) && parsed.length > 0) {
          setMessages(parsed);
        } else {
          setInitialGreeting();
        }
      } catch (e) {
        setInitialGreeting();
      }
    } else {
      setInitialGreeting();
    }
  }, []);

  // Guardar historial cuando cambien los mensajes
  useEffect(() => {
    if (messages.length > 0) {
      // Limitamos el historial para no saturar el localStorage
      const historyToSave = messages.slice(-MAX_HISTORY_MESSAGES);
      localStorage.setItem(STORAGE_KEY, JSON.stringify(historyToSave));
    }
  }, [messages]);

  const setInitialGreeting = () => {
    setMessages([
      { 
        role: 'model', 
        text: 'Hola, soy tu compañero de CalmaVibe. Estoy aquí para escucharte, sin juzgar. ¿Cómo te sientes en este momento?', 
        timestamp: Date.now() 
      }
    ]);
  };

  const clearChat = () => {
    if (window.confirm('¿Deseas borrar todo el historial de esta conversación?')) {
      localStorage.removeItem(STORAGE_KEY);
      setInitialGreeting();
    }
  };

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(scrollToBottom, [messages]);

  const detectEmergency = (text: string) => {
    const keywords = ['suicidio', 'matarme', 'morir', 'pastillas', 'sobredosis', 'cortarme', 'muerte', 'desaparecer'];
    const lower = text.toLowerCase();
    return keywords.some(k => lower.includes(k));
  };

  const handleSend = async (e?: React.FormEvent) => {
    if (e) e.preventDefault();
    if (!input.trim() || isLoading) return;

    const userMessage: Message = { role: 'user', text: input, timestamp: Date.now() };
    setMessages(prev => [...prev, userMessage]);
    setInput('');
    setIsLoading(true);

    const hasEmergency = detectEmergency(input);

    // Preparar historial para Gemini (limitado a los últimos mensajes para contexto relevante)
    const history = messages.slice(-10).map(m => ({
      role: m.role,
      parts: [{ text: m.text }]
    }));

    const responseText = await geminiService.getChatResponse(input, history);

    let finalResponse = responseText || "Estoy aquí para escucharte...";

    if (hasEmergency) {
      finalResponse += "\n\n--- IMPORTANTE ---\nPor favor, recuerda que no estás solo. Puedes llamar a la Línea de la Vida (México) al 800 911 2000 o al 024 en España. Tu vida es valiosa.";
    }

    const aiMessage: Message = { role: 'model', text: finalResponse, timestamp: Date.now() };
    setMessages(prev => [...prev, aiMessage]);
    setIsLoading(false);

    if (isVoiceEnabled) {
      playVoice(finalResponse);
    }
  };

  const playVoice = async (text: string) => {
    const sanitized = text.split('---')[0].trim();
    const audioBase64 = await geminiService.generateSpeech(sanitized, selectedVoice);
    if (audioBase64) {
      try {
        const ctx = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
        const binary = atob(audioBase64);
        const bytes = new Uint8Array(binary.length);
        for (let i = 0; i < binary.length; i++) bytes[i] = binary.charCodeAt(i);
        const int16 = new Int16Array(bytes.buffer);
        const buffer = ctx.createBuffer(1, int16.length, 24000);
        const channelData = buffer.getChannelData(0);
        for (let i = 0; i < int16.length; i++) channelData[i] = int16[i] / 32768.0;
        const source = ctx.createBufferSource();
        source.buffer = buffer;
        source.connect(ctx.destination);
        source.start();
      } catch (err) {
        console.error("Error al reproducir audio:", err);
      }
    }
  };

  return (
    <div className="flex flex-col h-[75vh] glass-effect rounded-3xl overflow-hidden shadow-2xl animate-fade-in">
      <div className="p-4 bg-white/10 flex justify-between items-center text-white border-b border-white/20">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-blue-400 rounded-full flex items-center justify-center text-xl shadow-inner">✨</div>
          <div>
            <h3 className="font-bold">Compañero CalmaVibe</h3>
            <span className="text-xs opacity-70">Memoria activada</span>
          </div>
        </div>
        <div className="flex gap-2">
          <button 
            onClick={clearChat}
            className="p-2 rounded-lg bg-white/10 hover:bg-red-400/30 transition-all"
            title="Limpiar Chat"
          >
            🗑️
          </button>
          <button 
            onClick={() => setIsVoiceEnabled(!isVoiceEnabled)}
            className={`p-2 rounded-lg transition-all ${isVoiceEnabled ? 'bg-green-400/50' : 'bg-white/10'}`}
            title="Activar Voz"
          >
            {isVoiceEnabled ? '🔊' : '🔇'}
          </button>
          <select 
            value={selectedVoice}
            onChange={(e) => setSelectedVoice(e.target.value as 'Kore' | 'Zephyr')}
            className="bg-white/10 rounded-lg px-2 text-xs outline-none cursor-pointer border border-white/10"
          >
            <option value="Zephyr" className="text-gray-800">Femenina</option>
            <option value="Kore" className="text-gray-800">Masculina</option>
          </select>
        </div>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-4 no-scrollbar">
        {messages.map((m, i) => (
          <div key={i} className={`flex ${m.role === 'user' ? 'justify-end' : 'justify-start'} animate-fade-in`}>
            <div className={`max-w-[85%] p-4 rounded-2xl ${
              m.role === 'user' 
              ? 'bg-blue-600 text-white rounded-tr-none shadow-lg' 
              : 'bg-white/90 text-gray-800 rounded-tl-none shadow-md'
            }`}>
              <p className="whitespace-pre-wrap leading-relaxed text-sm md:text-base">{m.text}</p>
              <span className="text-[10px] opacity-50 mt-2 block text-right">
                {new Date(m.timestamp).toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}
              </span>
            </div>
          </div>
        ))}
        {isLoading && (
          <div className="flex justify-start animate-pulse">
            <div className="bg-white/50 p-3 rounded-2xl rounded-tl-none text-gray-600 text-sm">
              Pensando...
            </div>
          </div>
        )}
