}

const SEARCH_CATEGORIES = [
  { id: 'psychologist', label: 'Psicólogos', query: 'psicólogos y terapeutas para ansiedad' },
  { id: 'clinic', label: 'Clínicas', query: 'clínicas de salud mental y psiquiatría' },
