];

declare const L: any; // Leaflet Global

const Directory: React.FC = () => {
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<{ text: string; chunks: GroundingChunk[] } | null>(null);
  const [userLocation, setUserLocation] = useState<{ lat: number; lng: number } | null>(null);
  const [mapCenter, setMapCenter] = useState<{ lat: number; lng: number } | null>(null);
  const [activeCategory, setActiveCategory] = useState<string>('');
  const [showSearchHere, setShowSearchHere] = useState(false);

  const mapRef = useRef<any>(null);
  const mapInstance = useRef<any>(null);
  const userMarker = useRef<any>(null);

  // Inicializar ubicación y Mapa
  useEffect(() => {
    const initLocation = () => {
      if (navigator.geolocation) {
        navigator.geolocation.getCurrentPosition(
          (pos) => {
            const coords = { lat: pos.coords.latitude, lng: pos.coords.longitude };
            setUserLocation(coords);
            setMapCenter(coords);
            initMap(coords);
          },
          (err) => {
            console.warn("Acceso a ubicación denegado", err);
            const defaultCoords = { lat: 19.4326, lng: -99.1332 }; // CDMX por defecto
            setMapCenter(defaultCoords);
            initMap(defaultCoords);
          }
        );
      } else {
        const defaultCoords = { lat: 19.4326, lng: -99.1332 };
        setMapCenter(defaultCoords);
        initMap(defaultCoords);
      }
    };

    initLocation();

    return () => {
      if (mapInstance.current) {
        mapInstance.current.remove();
        mapInstance.current = null;
      }
    };
  }, []);

  const initMap = (coords: { lat: number; lng: number }) => {
    if (!mapRef.current || mapInstance.current) return;

    mapInstance.current = L.map(mapRef.current, {
      center: [coords.lat, coords.lng],
      zoom: 13,
      zoomControl: true,
    });

    L.tileLayer('https://{s}.basemaps.cartocdn.com/rastertiles/voyager/{z}/{x}/{y}{r}.png', {
      attribution: '&copy; OpenStreetMap contributors'
    }).addTo(mapInstance.current);

    userMarker.current = L.marker([coords.lat, coords.lng], {
      icon: L.divIcon({
        className: 'user-location-marker',
        html: `<div class="w-4 h-4 bg-blue-500 border-2 border-white rounded-full shadow-lg animate-pulse"></div>`,
        iconSize: [16, 16],
      })
    }).addTo(mapInstance.current);

    mapInstance.current.on('moveend', () => {
      const center = mapInstance.current.getCenter();
      setMapCenter({ lat: center.lat, lng: center.lng });
      setShowSearchHere(true);
    });
  };

  const handleSearch = async (query: string, categoryId: string, customLat?: number, customLng?: number) => {
    setLoading(true);
    setActiveCategory(categoryId || activeCategory || 'psychologist');
    setShowSearchHere(false);

    const lat = customLat || mapCenter?.lat;
    const lng = customLng || mapCenter?.lng;

    const data = await geminiService.searchNearbyPlaces(query, lat, lng);
    setResults({ text: data.text, chunks: data.groundingChunks });
    setLoading(false);

    // Si buscamos en una nueva zona, centramos el mapa suavemente si es necesario
    if (customLat && customLng && mapInstance.current) {
      mapInstance.current.setView([customLat, customLng], 14);
    }
  };

  const handleSearchInThisArea = () => {
    const currentQuery = SEARCH_CATEGORIES.find(c => c.id === activeCategory)?.query || SEARCH_CATEGORIES[0].query;
    handleSearch(currentQuery, activeCategory);
  };

  return (
    <div className="glass-effect rounded-[2.5rem] p-6 md:p-10 text-white shadow-2xl max-w-6xl mx-auto animate-fade-in min-h-[85vh] border border-white/30">
      <div className="flex flex-col md:flex-row justify-between items-start mb-8 gap-4">
        <div>
          <h2 className="text-4xl font-bold mb-2 italic">Directorio de Apoyo</h2>
          <p className="opacity-80 text-lg font-light">Encuentra ayuda profesional y centros de bienestar donde los necesites.</p>
        </div>
        {!userLocation && (
          <div className="bg-orange-400/20 border border-orange-400/40 px-4 py-2 rounded-2xl text-xs text-orange-100 animate-pulse">
            📍 Activa tu ubicación para una mejor precisión
          </div>
        )}
      </div>

      <div className="relative mb-10">
        <div 
          ref={mapRef} 
          className="w-full h-[400px] md:h-[500px] rounded-[2rem] shadow-2xl overflow-hidden border border-white/20"
        ></div>

        {showSearchHere && (
          <button 
            onClick={handleSearchInThisArea}
            className="absolute top-6 left-1/2 -translate-x-1/2 z-[1000] bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-full font-bold shadow-2xl transition-all hover:scale-105 active:scale-95 border border-white/40 flex items-center gap-2"
          >
            <span>🔍</span> Buscar en esta zona
          </button>
        )}

        <div className="absolute bottom-6 right-6 z-[1000] flex flex-col gap-2">
           <button 
             onClick={() => {
               if (userLocation && mapInstance.current) {
                 mapInstance.current.setView([userLocation.lat, userLocation.lng], 15);
                 handleSearch(SEARCH_CATEGORIES.find(c => c.id === activeCategory)?.query || SEARCH_CATEGORIES[0].query, activeCategory, userLocation.lat, userLocation.lng);
               }
             }}
             className="bg-white/20 backdrop-blur-md p-3 rounded-full hover:bg-white/30 transition-all border border-white/30"
             title="Mi ubicación"
           >
             🏠
           </button>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-5 gap-3 mb-10">
        {SEARCH_CATEGORIES.map((cat) => (
          <button
            key={cat.id}
            onClick={() => handleSearch(cat.query, cat.id)}
            disabled={loading}
            className={`p-4 rounded-3xl flex flex-col items-center gap-3 transition-all border ${
              activeCategory === cat.id 
              ? 'bg-gradient-to-br from-blue-500 to-indigo-600 border-white shadow-xl scale-105' 
              : 'bg-white/10 border-white/10 hover:bg-white/20'
            }`}
          >
            <span className="text-3xl">
              {cat.id === 'psychologist' ? '🧠' : 
               cat.id === 'clinic' ? '🏥' : 
               cat.id === 'acupunture' ? '📍' : 
               cat.id === 'emergency' ? '🆘' : '🧘'}
            </span>
            <span className="text-[10px] font-black uppercase tracking-widest">{cat.label}</span>
          </button>
        ))}
      </div>

      {loading ? (
        <div className="py-24 flex flex-col items-center justify-center animate-pulse">
          <div className="w-16 h-16 border-4 border-white/10 border-t-white rounded-full animate-spin mb-6"></div>
          <p className="text-2xl font-light italic tracking-wide">Explorando el mapa con IA...</p>
        </div>
      ) : results ? (
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 animate-fade-in">
          <div className="lg:col-span-1 space-y-4">
            <h3 className="text-xl font-bold mb-4 flex items-center gap-2">
              <span>📍</span> Lugares Encontrados
            </h3>
            <div className="flex flex-col gap-3 max-h-[600px] overflow-y-auto pr-2 no-scrollbar">
              {results.chunks.filter(c => c.maps).map((chunk, idx) => (
                <a 
                  key={idx} 
                  href={chunk.maps!.uri} 
                  target="_blank" 
                  rel="noopener noreferrer"
                  className="bg-white/10 hover:bg-white/20 p-5 rounded-2xl border border-white/10 transition-all flex justify-between items-center group shadow-md"
                >
                  <div className="flex-1">
                    <h4 className="font-bold text-white group-hover:text-blue-200 transition-colors leading-tight">{chunk.maps!.title}</h4>
                    <span className="text-[10px] bg-blue-500/30 px-2 py-0.5 rounded-full mt-2 inline-block">Ver detalles</span>
                  </div>
                  <span className="text-2xl opacity-50 group-hover:opacity-100 group-hover:translate-x-1 transition-all">➔</span>
                </a>
              ))}
              {results.chunks.filter(c => c.maps).length === 0 && (
                <div className="bg-white/5 p-8 rounded-3xl text-center border border-white/5">
                  <p className="opacity-50 italic text-sm">Explora la descripción detallada para más opciones.</p>
                </div>
              )}
