import { GoogleGenAI, Type, GenerateContentResponse, Modality } from "@google/genai";

const API_KEY = process.env.API_KEY;

export class GeminiService {
  private ai: any;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: API_KEY! });
  }

  async getChatResponse(message: string, history: { role: 'user' | 'model', parts: { text: string }[] }[]) {
    const systemInstruction = `
      Eres el "Acompañante de CalmaVibe", una IA diseñada específicamente para ofrecer apoyo emocional profundo a personas que atraviesan ansiedad o depresión. 
      Tu tono debe ser extremadamente cálido, compasivo, paciente y profundamente empático.

      OBJETIVOS CLAVE:
      1. RESPUESTAS LARGAS Y REFLEXIVAS: No te limites a frases cortas. Elabora tus pensamientos, ofrece metáforas reconfortantes sobre la naturaleza (ríos, nubes, estaciones) y profundiza en la validación de lo que el usuario siente.
      2. ESCUCHA ACTIVA: Refleja lo que el usuario te dice para que se sienta escuchado. Ejemplo: "Entiendo que hoy te sientes como si estuvieras bajo una tormenta pesada..."
      3. SIN JUICIOS: Crea un espacio donde cualquier pensamiento sea aceptable.
      4. HUMANIDAD: Habla con naturalidad, como un amigo sabio y tranquilo.

      REGLAS CRÍTICAS DE SEGURIDAD:
      - Si el usuario menciona autolesión, suicidio o planes de muerte, responde con ternura infinita, valida su inmenso dolor, pero insiste con firmeza y amor en que busque ayuda profesional inmediata. Proporciona recursos como la Línea de la Vida o servicios de emergencia locales.
      - NO recetes medicamentos ni des diagnósticos clínicos.
      - Evita sonar como un cuestionario médico. Prioriza la conexión emocional.
    `;

    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: [
          ...history.map(h => ({ role: h.role, parts: h.parts })),
          { role: 'user', parts: [{ text: message }] }
        ],
        config: {
          systemInstruction,
          temperature: 0.9,
          topP: 0.95,
        },
      });

      return response.text;
    } catch (error) {
      console.error("Gemini Error:", error);
      return "En este momento me cuesta encontrar las palabras, pero quiero que sepas que no estás solo. Estoy aquí, respirando contigo. Inténtalo de nuevo en un momento.";
    }
  }

  async generateSpeech(text: string, voice: 'Kore' | 'Zephyr') {
    try {
      const response = await this.ai.models.generateContent({
        model: "gemini-2.5-flash-preview-tts",
        contents: [{ parts: [{ text }] }],
        config: {
          responseModalities: [Modality.AUDIO],
          speechConfig: {
            voiceConfig: {
              prebuiltVoiceConfig: { voiceName: voice },
            },
          },
        },
      });

      return response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    } catch (error) {
      console.error("TTS Error:", error);
      return null;
    }
  }

  async searchNearbyPlaces(query: string, lat?: number, lng?: number) {
    try {
      const toolConfig = lat && lng ? {
        retrievalConfig: {
          latLng: {
            latitude: lat,
            longitude: lng
          }
        }
      } : undefined;

      const response = await this.ai.models.generateContent({
        model: "gemini-2.5-flash",
        contents: `
          Encuentra ${query} cercanos a la ubicación proporcionada. 
          1. Proporciona una lista detallada con nombres y descripciones breves en lenguaje natural.
          2. AL FINAL DE TU RESPUESTA, incluye obligatoriamente un bloque de código JSON con el siguiente formato exacto: 
          JSON_MARKERS: [{"name": "Nombre", "lat": 0.0, "lng": 0.0, "uri": "URL de Google Maps"}]
          Asegúrate de incluir las coordenadas de latitud y longitud para cada lugar encontrado.
        `,
        config: {
          tools: [{ googleMaps: {} }],
          toolConfig
        },
      });

      const text = response.text;
      const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];

      return { text, groundingChunks };
    } catch (error) {
      console.error("Maps Grounding Error:", error);
      return { text: "No pude localizar lugares en este momento. Por favor verifica tu conexión o permisos de ubicación.", groundingChunks: [] };
    }
  }
}

