              iconSize: [24, 24],
            })
          }).addTo(markersLayer.current);

          marker.bindPopup(`
            <div class="p-2 min-w-[150px]">
              <h4 class="font-bold text-gray-800 text-sm mb-1">${m.name}</h4>
              <a href="${m.uri}" target="_blank" class="text-xs text-blue-600 font-bold hover:underline">Ver en Google Maps</a>
            </div>
          `);
        }
      });

      // Ajustar vista del mapa para mostrar marcadores
      if (markers.length > 0 && mapInstance.current) {
        mapInstance.current.fitBounds(markersLayer.current.getBounds(), { padding: [50, 50] });
      }
    }

    setLoading(false);

    if (customLat && customLng && mapInstance.current && markers.length === 0) {
      mapInstance.current.setView([customLat, customLng], 14);
    }
  };

  const handleSearchInThisArea = () => {
    const currentQuery = SEARCH_CATEGORIES.find(c => c.id === activeCategory)?.query || SEARCH_CATEGORIES[0].query;
    handleSearch(currentQuery, activeCategory);
  };

  const cleanTextResponse = (text: string) => {
    // Eliminar la parte del JSON del texto mostrado al usuario
    const markerPrefix = "JSON_MARKERS:";
    const index = text.indexOf(markerPrefix);
    if (index !== -1) return text.substring(0, index).trim();
    return text;
  };

  return (
    <div className="glass-effect rounded-[2.5rem] p-6 md:p-10 text-white shadow-2xl max-w-6xl mx-auto animate-fade-in min-h-[85vh] border border-white/30">
      <div className="flex flex-col md:flex-row justify-between items-start mb-8 gap-4">
        <div>
          <h2 className="text-4xl font-bold mb-2 italic">Directorio de Apoyo</h2>
          <p className="opacity-80 text-lg font-light">Encuentra ayuda profesional y centros de bienestar donde los necesites.</p>
        </div>
        {!userLocation && (
          <div className="bg-orange-400/20 border border-orange-400/40 px-4 py-2 rounded-2xl text-xs text-orange-100 animate-pulse">
            📍 Activa tu ubicación para una mejor precisión
          </div>
        )}
      </div>

      <div className="relative mb-10">
        <div 
          ref={mapRef} 
          className="w-full h-[400px] md:h-[500px] rounded-[2rem] shadow-2xl overflow-hidden border border-white/20"
        ></div>

        {showSearchHere && (
          <button 
            onClick={handleSearchInThisArea}
            className="absolute top-6 left-1/2 -translate-x-1/2 z-[1000] bg-blue-600 hover:bg-blue-700 text-white px-6 py-3 rounded-full font-bold shadow-2xl transition-all hover:scale-105 active:scale-95 border border-white/40 flex items-center gap-2"
          >
            <span>🔍</span> Buscar en esta zona
          </button>
        )}

        <div className="absolute bottom-6 right-6 z-[1000] flex flex-col gap-2">
           <button 
             onClick={() => {
               if (userLocation && mapInstance.current) {
                 mapInstance.current.setView([userLocation.lat, userLocation.lng], 15);
                 handleSearch(SEARCH_CATEGORIES.find(c => c.id === activeCategory)?.query || SEARCH_CATEGORIES[0].query, activeCategory, userLocation.lat, userLocation.lng);
               }
             }}
             className="bg-white/20 backdrop-blur-md p-3 rounded-full hover:bg-white/30 transition-all border border-white/30"
             title="Mi ubicación"
           >
             🏠
           </button>
        </div>
      </div>

      <div className="grid grid-cols-2 md:grid-cols-5 gap-3 mb-10">
        {SEARCH_CATEGORIES.map((cat) => (
          <button
            key={cat.id}
            onClick={() => handleSearch(cat.query, cat.id)}
            disabled={loading}
            className={`p-4 rounded-3xl flex flex-col items-center gap-3 transition-all border ${
              activeCategory === cat.id 
              ? 'bg-gradient-to-br from-blue-500 to-indigo-600 border-white shadow-xl scale-105' 
              : 'bg-white/10 border-white/10 hover:bg-white/20'
            }`}
          >
            <span className="text-3xl">
              {cat.id === 'psychologist' ? '🧠' : 
               cat.id === 'clinic' ? '🏥' : 
               cat.id === 'acupunture' ? '📍' : 
               cat.id === 'emergency' ? '🆘' : '🧘'}
            </span>
            <span className="text-[10px] font-black uppercase tracking-widest">{cat.label}</span>
          </button>
        ))}
      </div>

      {loading ? (
        <div className="py-24 flex flex-col items-center justify-center animate-pulse">
          <div className="w-16 h-16 border-4 border-white/10 border-t-white rounded-full animate-spin mb-6"></div>
